] { apiGames.filter { $0.isFinal } }        init() {        loadUserPreferences()        liveGamesSport = defaultSport   // Initialize live games to default        standingsSport = defaultSport   // Initialize standings to default        isInitializing = false  // Now didSet will work normally                Task {            await loadGames(for: liveGamesSport)            await loadStandings(for: standingsSport)            await loadFavoriteGames()        }        startAutoRefresh()    }        deinit { refreshTimer?.invalidate() }        // -- Data Loading        @MainActor    func loadGames(for sport: Sport) async {        isLoading = true        errorMessage = nil        liveGamesSport = sport  // Track what sport games are loaded for                do {            let games = try await APIService.shared.fetchGames(for: sportEndpoint(sport))            apiGames = games.sorted { game1, game2 in                if game1.isLive != game2.isLive { return game1.isLive }                if game1.isScheduled != game2.isFinal { return game1.isScheduled }                return game1.date < game2.date            }            lastUpdate = Date()        } catch {            errorMessage = "Unable to load games. Check your connection."            print("Failed to load games: \(error)")        }                isLoading = false    }        @MainActor    func loadStandings(for sport: Sport) async {        standingsLoading = true        standingsSport = sport  // Track what sport standings are loaded for (separate from games!)                do {            let result = try await APIService.shared.fetchStandings(for: sportEndpoint(sport))            conferenceStandings = result.conferences            standings = result.conferences.first?.entries ?? result.entries        } catch {            print("Failed to load standings: \(error)")            standings = []            conferenceStandings = []        }                standingsLoading = false    }        @MainActor    func loadFavoriteGames() async {        var allFavoriteGames: [(game: APIGame, sport: Sport)] = []                for sport in Sport.allCases {            do {                let games = try await APIService.shared.fetchGames(for: sportEndpoint(sport))                let favoriteGamesForSport = games.filter { game in                    let teams = [                        game.homeTeam?.team.displayName,                        game.awayTeam?.team.displayName,                        game.homeTeam?.team.abbreviation,                        game.awayTeam?.team.abbreviation                    ].compactMap { $0 }                    return teams.contains { favoriteTeams.contains($0) }                }                // Store each game with its sport                allFavoriteGames.append(contentsOf: favoriteGamesForSport.map { (game: $0, sport: sport) })            } catch {                print("Failed to load \(sport.rawValue) games for favorites")            }        }                apiFavoriteGames = allFavoriteGames.sorted { item1, item2 in            if item1.game.isLive != item2.game.isLive { return item1.game.isLive }            return item1.game.date < item2.game.date        }    }        func refresh(for sport: Sport) async {        await loadGames(for: sport)        await loadStandings(for: sport)        if !favoriteTeams.isEmpty { await loadFavoriteGames() }    }        // Favorites        func toggleFavorite(_ team: String) {        if favoriteTeams.contains(team) {            favoriteTeams.remove(team)        } else {            favoriteTeams.insert(team)        }    }        func isFavorite(_ team: String) -> Bool {        favoriteTeams.contains(team)    }        func clearAllFavorites() {        favoriteTeams.removeAll()    }        // Private Helpers        private func startAutoRefresh() {        refreshTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { _ in            Task { @MainActor in                if !self.liveGames.isEmpty || self.apiFavoriteGames.contains(where: { $0.game.isLive }) {                    await self.loadGames(for: self.liveGamesSport)  // Use liveGamesSport, not affected by standings                    if !self.apiFavoriteGames.isEmpty { await self.loadFavoriteGames() }                }            }        }    }        private func loadUserPreferences() {        // Load default sport (from Settings)        if let sportRaw = UserDefaults.standard.string(forKey: "defaultSport"),           let sport = Sport(rawValue: sportRaw) {            defaultSport = sport        } else if let oldSportRaw = UserDefaults.standard.string(forKey: "selectedSport"),                  let sport = Sport(rawValue: oldSportRaw) {            // Migration: read old key if new one doesn't exist            defaultSport = sport            UserDefaults.standard.set(sport.rawValue, forKey: "defaultSport")            UserDefaults.standard.removeObject(forKey: "selectedSport")        }                // Load favorite teams        if let savedTeams = UserDefaults.standard.array(forKey: "favoriteTeams") as? [String] {            favoriteTeams = Set(savedTeams)        }    }        private func sportEndpoint(_ sport: Sport) -> APIService.SportEndpoint {        switch sport {        case .nba: return .nba        case .nfl: return .nfl        case .mlb: return .mlb        case .nhl: return .nhl        }    }        private func convertToGame(_ apiGame: APIGame, sport: Sport) -> Game {        let status: GameStatus        if apiGame.isLive { status = .live }        else if apiGame.isFinal { status = .final }        else { status = .upcoming(time: extractGameTime(from: apiGame.date)) }                return Game(            homeTeam: apiGame.homeTeam?.team.displayName ?? "Home",            awayTeam: apiGame.awayTeam?.team.displayName ?? "Away",            homeScore: Int(apiGame.homeTeam?.score ?? "0") ?? 0,            awayScore: Int(apiGame.awayTeam?.score ?? "0") ?? 0,            status: status,            quarter: getQuarterString(apiGame, sport: sport),            timeRemaining: apiGame.isLive ? apiGame.displayClock : nil,            sport: sport,            espnGameId: apiGame.id,            homeLogoURL: apiGame.homeTeam?.team.logo,            awayLogoURL: apiGame.awayTeam?.team.logo        )    }        private func getQuarterString(_ game: APIGame, sport: Sport) -> String? {        if game.isFinal { return "Final" }        guard game.isLive else { return nil }                switch sport {        case .nba: return game.period > 4 ? "OT" : "Q\(game.period)"        case .nfl: return ["1st", "2nd", "3rd", "4th", "OT"][min(game.period - 1, 4)]        case .mlb:            if let detail = game.status.type.shortDetail {                if detail.contains("Top") { return "Top \(game.period)" }                if detail.contains("Bot") { return "Bot \(game.period)" }            }            return "Inning \(game.period)"        case .nhl: return game.period > 3 ? "OT" : "Period \(game.period)"        }    }        private func extractGameTime(from dateString: String) -> String {        if let date = ISO8601DateFormatter().date(from: dateString) {            let formatter = DateFormatter()            formatter.timeStyle = .short            return formatter.string(from: date)        }        return "TBD"    }}